/* Evidence: cmem-worked-cmem-objects-storage-lifetime-4 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 7424; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


struct lifetime_handle { int value; unsigned generation; int live; };

static int worked_cmem_objects_storage_lifetime_4(const struct lifetime_handle *item, unsigned expected) {
  if (item == NULL || !item->live) return -1;
  if (item->generation != expected) return -2;
  return item->value;
}

int main(void) {
  struct lifetime_handle item = { 9, 3u, 1 };
  int stale = worked_cmem_objects_storage_lifetime_4(&item, 4u);
  int live = worked_cmem_objects_storage_lifetime_4(&item, 3u);
  int invariant = stale == -2 && live == 9;
  printf("lifetime stale=%d live=%d invariant=%d\n", stale, live, invariant);
  return invariant ? 0 : 1;
}

